const crypto = require('crypto');

const apiBaseUrl = $env.IMPERIUM_API_BASE_URL;
const webhookSecret = $env.INTERNAL_WEBHOOK_SECRET;
const input = $input.first().json.body ?? $input.first().json;
const requiredFields = [
  'task_id',
  'session_id',
  'task_type',
  'week_start',
  'week_end',
  'user_message_id',
  'user_answer',
  'callback_url',
  'wr_attach_url',
];

for (const field of requiredFields) {
  if (!input[field]) {
    throw new Error(`Missing required WR answers payload field: ${field}`);
  }
}

if (input.task_type !== 'weekly_report.answers.integrate') {
  throw new Error(`Unsupported task_type for WR answers workflow: ${input.task_type}`);
}

const expectedCallbackUrl = `/api/internal/ai/tasks/${input.task_id}/result`;
const expectedAttachUrl = `/api/internal/weekly-review/${input.session_id}/attach-ai-result`;
if (input.callback_url !== expectedCallbackUrl) {
  throw new Error(`Unexpected callback_url. Expected ${expectedCallbackUrl}`);
}
if (input.wr_attach_url !== expectedAttachUrl) {
  throw new Error(`Unexpected wr_attach_url. Expected ${expectedAttachUrl}`);
}
if (!apiBaseUrl) {
  throw new Error('Missing IMPERIUM_API_BASE_URL environment variable.');
}
if (!webhookSecret) {
  throw new Error('Missing INTERNAL_WEBHOOK_SECRET environment variable.');
}

const resultBody = {
  result_type: 'weekly_report.draft',
  result_payload: {
    title: 'Draft WR from dry-run answer integration',
    summary: 'Dry-run draft generated after integrating the latest WR answer.',
    sections: [
      {
        title: 'Answer integration dry-run',
        content: `User answer captured for message ${input.user_message_id}: ${input.user_answer}`,
      },
    ],
    questions_answered: [
      {
        message_id: input.user_message_id,
        answer: input.user_answer,
      },
    ],
    source: 'qwen_dry_run_answers_integrate',
  },
  model_used: 'qwen2.5:7b-instruct',
  provider: 'qwen-dry-run',
  confidence: 0.7,
  raw_payload: {
    workflow: 'IMPERIUM_WR_ANSWERS_INTEGRATE_QWEN_DRY_RUN',
    dry_run: true,
  },
};

const rawBody = JSON.stringify(resultBody);
const timestamp = Math.floor(Date.now() / 1000).toString();
const message = `${timestamp}.${rawBody}`;
const signature = crypto.createHmac('sha256', webhookSecret).update(message).digest('hex');

return [
  {
    json: {
      ...input,
      callbackRawBody: rawBody,
      callbackTimestamp: timestamp,
      callbackSignature: signature,
      callbackIdempotencyKey: `wr_answers_integrate_result_${input.task_id}`,
    },
  },
];

const crypto = require('crypto');

function normalizeHttpJson(value) {
  if (value && typeof value === 'object' && value.body !== undefined) {
    value = value.body;
  }
  if (value && typeof value === 'object' && value.data !== undefined) {
    value = value.data;
  }
  if (typeof value === 'string') {
    try {
      return JSON.parse(value);
    } catch (error) {
      throw new Error('HTTP response body was not valid JSON.');
    }
  }
  return value;
}

const webhookSecret = $env.INTERNAL_WEBHOOK_SECRET;
const previous = $('Validate Payload and Sign Result Callback').first().json;
const callbackResponse = normalizeHttpJson($input.first().json);
const resultId = callbackResponse?.result_id;
if (!resultId) {
  const keys = callbackResponse && typeof callbackResponse === 'object' ? Object.keys(callbackResponse).join(',') : typeof callbackResponse;
  throw new Error(`AI result callback did not return result_id. Response shape: ${keys}`);
}

const attachBody = { ai_result_id: resultId };
const rawBody = JSON.stringify(attachBody);
const timestamp = Math.floor(Date.now() / 1000).toString();
const message = `${timestamp}.${rawBody}`;
const signature = crypto.createHmac('sha256', webhookSecret).update(message).digest('hex');

return [
  {
    json: {
      ...previous,
      result_id: resultId,
      attachRawBody: rawBody,
      attachTimestamp: timestamp,
      attachSignature: signature,
      attachIdempotencyKey: `wr_answers_integrate_attach_${previous.session_id}_${resultId}`,
    },
  },
];

return [
  {
    json: {
      status: 'ok',
      workflow: 'IMPERIUM_WR_ANSWERS_INTEGRATE_QWEN_DRY_RUN',
      task_id: $('Normalize Callback and Sign Attach').first().json.task_id,
      session_id: $('Normalize Callback and Sign Attach').first().json.session_id,
      result_id: $('Normalize Callback and Sign Attach').first().json.result_id,
      message: 'Dry-run WR answer integration completed and attached as draft proposal.',
    },
  },
];
